class MyLinkedList {
public:
    MyLinkedList() {
        head = nullptr;
        tail = nullptr;
        size = 0;
    }

    int get(int index) {
        if (index < 0 || index >= size) return -1;
        int currIndex = 0;
        Node* curr = head;
        while (currIndex < index) {
            curr = curr->next;
            currIndex++;
        }
        return curr->val;
    }

    void addAtHead(int val) {
        Node* newNode = new Node(val);
        if (size == 0) {
            head = newNode;
            tail = newNode;
        } else {
            newNode->next = head;
            head = newNode;
        }
        size++;
    }

    void addAtTail(int val) {
        Node* newNode = new Node(val);
        if (size == 0) {
            head = newNode;
            tail = newNode;
        } else {
            tail->next = newNode;
            tail = newNode;
        }
        size++;
    }

    void addAtIndex(int index, int val) {
        if (index > size) return;
        if (index == 0) addAtHead(val);
        else if (index == size) addAtTail(val);
        else {
            int currIndex = 0;
            Node* curr = head;
            while (currIndex < index - 1) {
                curr = curr->next;
                currIndex++;
            }
            Node* newNode = new Node(val);
            newNode->next = curr->next;
            curr->next = newNode;
            size++;
        }
    }

    void deleteAtIndex(int index) {
        if (index >= size) return;
        if (index == 0) {
            Node* temp = head;
            head = head->next;
            delete temp;
        } else {
            int currIndex = 0;
            Node* curr = head;
            while (currIndex < index - 1) {
                curr = curr->next;
                currIndex++;
            }
            Node* temp = curr->next;
            curr->next = temp->next;
            delete temp;
        }
        size--;
    }
private:
    struct Node {
        int val;
        Node* next;
        Node(int x) : val(x), next(nullptr) {}
    };
    Node* head;
    Node* tail;
    int size;
};
```
